import React, { useState, useEffect } from "react";
import axios from "axios";
import "./App.css";

// ----------------- PasswordInput Component -----------------
function PasswordInput({ value, onChange, placeholder }) {
  const [visible, setVisible] = useState(false);

  return (
    <div className="password-wrapper">
      <input
        type={visible ? "text" : "password"}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        required
      />
      <button
        type="button"
        className="toggle-password"
        onClick={() => setVisible(!visible)}
      >
        {visible ? "🙈" : "👁️"}
      </button>
    </div>
  );
}

// ----------------- Login Component -----------------
function Login({ onLogin }) {
  const [form, setForm] = useState({ email: "", password: "" });
  const [message, setMessage] = useState("");

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/login", form);
      localStorage.setItem("token", res.data.token);
      onLogin(res.data.user);
    } catch (err) {
      setMessage("Invalid email or password");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>Login</h2>
        <p className="subtitle">Welcome back! Please log in.</p>
        <form onSubmit={handleLogin}>
          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              placeholder="Enter your email"
              required
            />
          </div>
          <div className="form-group">
            <label>Password</label>
            <PasswordInput
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              placeholder="Enter your password"
            />
          </div>
          <button className="btn-primary" type="submit">
            Login
          </button>
        </form>
        {message && <div className="message error">{message}</div>}
      </div>
    </div>
  );
}

// ----------------- Register Component -----------------
function Register({ onRegister }) {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [message, setMessage] = useState("");

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("http://localhost:5000/api/register", form);
      setMessage("Registration successful. Please login.");
      onRegister();
    } catch (err) {
      setMessage("Error registering. Try again.");
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>Register</h2>
        <p className="subtitle">Create your account</p>
        <form onSubmit={handleRegister}>
          <div className="form-group">
            <label>Name</label>
            <input
              type="text"
              value={form.name}
              onChange={(e) => setForm({ ...form, name: e.target.value })}
              placeholder="Enter your name"
              required
            />
          </div>
          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              placeholder="Enter your email"
              required
            />
          </div>
          <div className="form-group">
            <label>Password</label>
            <PasswordInput
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              placeholder="Create a password"
            />
          </div>
          <button className="btn-primary" type="submit">
            Register
          </button>
        </form>
        {message && (
          <div
            className={`message ${
              message.includes("successful") ? "success" : "error"
            }`}
          >
            {message}
          </div>
        )}
      </div>
    </div>
  );
}

// ----------------- Dashboard Component -----------------
function Dashboard({ user, onLogout }) {
  return (
    <div className="container">
      <div className="dashboard">
        <div className="dashboard-header">
          <h2>Hello, {user.name} 👋</h2>
          <button className="btn-logout" onClick={onLogout}>
            Logout
          </button>
        </div>
        <p>Welcome to your finance logger dashboard.</p>
      </div>
    </div>
  );
}

// ----------------- Main App -----------------
function App() {
  const [user, setUser] = useState(null);
  const [view, setView] = useState("login");

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (token) {
      // In a real app, decode token or fetch user
      setUser({ name: "Demo User", email: "demo@example.com" });
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    setUser(null);
    setView("login");
  };

  if (user) {
    return <Dashboard user={user} onLogout={handleLogout} />;
  }

  return view === "login" ? (
    <Login onLogin={(user) => setUser(user)} />
  ) : (
    <Register onRegister={() => setView("login")} />
  );
}

export default App;
